INSERT INTO public.photos VALUES (23195, 'Agrupaciâ”œâ”‚n Jubilados RENFE 2010', 'Foto: Rusolera, febrero de 2010. Sede de la Agrupaciâ”œâ”‚n de Pensionistas y Jubilados de RENFE, en la avenida Josâ”œÂ® Anselmo Clavâ”œÂ® de Zaragoza. El mismo aâ”œâ–’o de la foto, este edificio neomudâ”œÂ®jar serâ”œÃ­ derribado. Fuente: zaragozaciudad.net/zaragozafluye/2010/080301-sede-de-la-a...', 2010, 2010, 2010, 'Siglo XXI', 'DELICIAS', 41.65289600, -0.89371300, '0101000020E6100000505260014C99ECBF38D89B1892D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21496097670.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21496097670.webp', 'https://www.flickr.com/photos/zaragozaantigua/21496097670/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23220, 'Derribo Averly 2016', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 17 de la calle del Trovador durante el derribo de la veterana y referencial fundiciâ”œâ”‚n Averly que, activa desde 1880 y hasta 2011, fue demolida en 2/3 de su original extensiâ”œâ”‚n para dar paso, con el beneplâ”œÃ­cito de los poderes econâ”œâ”‚micos de la ciudad, a una necesaria promociâ”œâ”‚n privada de 120 viviendas de lujo de la constructora Brial cuya ejecuciâ”œâ”‚n comenzarâ”œÃ­ a principios de 2021, y cuyas llaves se entregarâ”œÃ­n en 2022-2023. Al fondo, entorno de la antigua estaciâ”œâ”‚n de Zaragoza-El Portillo.', 2016, 2016, 2016, 'Siglo XXI', 'DELICIAS', 41.65447200, -0.89510600, '0101000020E61000000E828E56B5A4ECBFE8120EBDC5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50678763063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50678763063.webp', 'https://www.flickr.com/photos/zaragozaantigua/50678763063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23234, 'Cuartel del Cid 2021', 'El cuartel de Caballerâ”œÂ¡a del Portillo, llamado luego del Cid, fue levantado en 1775 a instancias de Ramâ”œâ”‚n Pignatelli, segâ”œâ•‘n proyecto de Pedro Pablo Camâ”œâ”‚n. Se alzâ”œâ”‚ en el solar ocupado desde 1766 como Ã”Ã‡Â£tinglado de artillerâ”œÂ¡aÃ”Ã‡Ã˜ (polvorâ”œÂ¡n y armerâ”œÂ¡a), junto al convento de los Agustinos Descalzos (1602), derruido en los Sitios de 1808-1809 y cuyos terrenos sirvieron para ampliar el cuartel. Entre 1968 y 1976 fue derribado, conservando su tapia recayente al paseo de Marâ”œÂ¡a Agustâ”œÂ¡n. En 2021 se realizaron prospecciones arqueolâ”œâ”‚gicas con miras a construir viviendas en el solar, y aparecieron viviendas islâ”œÃ­micas, estructuras medievales y restos del cuartel. Una vez arrasado todo con la autorizaciâ”œâ”‚n de la comisiâ”œâ”‚n de Patrimonio del Gobierno de Aragâ”œâ”‚n, en 2022 se comienza la construcciâ”œâ”‚n allâ”œÂ¡ de una urbanizaciâ”œâ”‚n de lujo, conservando parte del muro y la puerta trasera del recinto militar. En la foto, vista del yacimiento arqueolâ”œâ”‚gico en agosto de 2021, con el Edificio Pignatelli y el de la Maternidad al fondo. A la derecha, fuera de plano, el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n.', 2021, 2021, 2021, 'Siglo XXI', 'DELICIAS', 41.65422300, -0.89269200, '0101000020E61000009ED32CD0EE90ECBF40A54A94BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51868764065.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51868764065.webp', 'https://www.flickr.com/photos/zaragozaantigua/51868764065/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23271, 'Campo del Sepulcro 1808', '"Batalla de las Heras, en la cual los franceses, intentando forzar el punto de Buena Vista y penetrar en Zaragoza fueron rechazados gloriosamente por los Aragoneses, y forzados a situarse fuera del tiro de caâ”œâ–’â”œâ”‚n de la Ciudad", Serie Ruinas de Zaragoza, de Juan Gâ”œÃ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œÃ­diz, 1812. La batalla de las Eras (una zona agrâ”œÂ¡cola de la periferia de la ciudad), o del Campo del Sepulcro, tuvo lugar el 15 de junio de 1808, donde dâ”œÂ®cadas despuâ”œÂ®s se levantarâ”œÂ¡a la Estaciâ”œâ”‚n de Ferrocarril del mismo nombre (Campo Sepulcro). De resultas del combate, los soldados franceses no tuvieron â”œÂ®xito en su ataque, y se retiraron. Al fondo, se eleva el castillo de La Aljaferâ”œÂ¡a. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65251400, -0.89476300, '0101000020E61000009677D503E6A1ECBF5017299485D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15266672542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15266672542.webp', 'https://www.flickr.com/photos/zaragozaantigua/15266672542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23316, 'Campo Sepulcro c.1912', 'La apertura de la lâ”œÂ¡nea Zaragoza-Madrid el 25 de mayo de 1863 supuso la inauguraciâ”œâ”‚n de la estaciâ”œâ”‚n de Campo Sepulcro, recinto provisional que acogiâ”œâ”‚ los primeros viajeros de la lâ”œÂ¡nea Madrid-Zaragoza-Alicante (MZA). En 1896 se inaugurâ”œâ”‚ la estaciâ”œâ”‚n definitiva, proyectada con aires clasicistas por el ingeniero Lâ”œâ”‚pez de Letona, con su larga fachada de 144 metros de longitud de la que sobresale en planta y altura un gran pabellâ”œâ”‚n central, que en la imagen centra la escena, acompaâ”œâ–’ado de dos pabellones algo mâ”œÃ­s pequeâ”œâ–’os en los extremos hasta los que se dispone una marquesina corrida para proteger de la solanera canicular. La parte metâ”œÃ­lica de su estructura provenâ”œÂ¡a de los cercanos talleres Averly, salvo la armadura de vigas de la cubierta, que era bilbaâ”œÂ¡na, y los ladrillos y tejas de los tejares locales. Un acabado final mâ”œÃ­s que digno, por encima de la media de otras estaciones peninsulares y aun europeas. En 1967, tras el cierre de las estaciones de Cariâ”œâ–’ena, Utrillas y Caminreal pasâ”œâ”‚ a ser la principal estaciâ”œâ”‚n de la ciudad. En 1973, el ente gestor RENFE procediâ”œâ”‚ a su "ampliaciâ”œâ”‚n y reforma", es decir, a su derribo integral, sustituyâ”œÂ®ndola por otra estaciâ”œâ”‚n moderna y de nueva planta, y cambiando su denominaciâ”œâ”‚n por la de Zaragoza-El Portillo (aunque estaba proyectado que se llamara "de Goya"), hasta que en 2003 fue a su vez sustituida por la actual estaciâ”œâ”‚n de Zaragoza-Delicias. En la imagen, vista de la fachada principal de la estaciâ”œâ”‚n MZA de Campo Sepulcro y su explanada de ingreso desde el paseo de las Estaciones por donde circulaba el tranvâ”œÂ¡a de la lâ”œÂ¡nea de Madrid, que la conectaba con la plaza de la Constituciâ”œâ”‚n.', 1912, 1912, 1912, 'Anos 10', 'DELICIAS', 41.65216800, -0.89483300, '0101000020E6100000CE35CCD078A2ECBFB6BFB33D7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14781246727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14781246727.webp', 'https://www.flickr.com/photos/zaragozaantigua/14781246727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23319, 'Fundiciâ”œâ”‚n Averly c.1900', 'Mudados desde la calle San Miguel en 1880 a una nueva ubicaciâ”œâ”‚n mâ”œÃ­s espaciosa en Campo Sepulcro, junto a la homâ”œâ”‚nima estaciâ”œâ”‚n de ferrocarril, Averly inicia una etapa de crecimiento y producciâ”œâ”‚n de raâ”œÂ¡les para tranvâ”œÂ¡as, turbinas hidrâ”œÃ­ulicas, engranajes, poleas, cojinetes, elementos de transmisiâ”œâ”‚n, ruedas dentadas, material sanitario especializado, maquinaria e instalaciones de molinerâ”œÂ¡a, panaderâ”œÂ¡a, extracciâ”œâ”‚n de aceites y vinos, generadores y autoclaves de vapor, instalaciones para riegos y material para la agricultura, etc. En la ciudad, y en el terreno de la fundiciâ”œâ”‚n artâ”œÂ¡stica, reconocemos obras de Averly en la estatua del Justicia (Plaza de Aragâ”œâ”‚n), el leâ”œâ”‚n del Batallador (Cabezo de Buena Vista), la Fuente de la Samaritana (Plaza del Justicia), la Fuente de las Garzas (Plaza de Utrillas), ornamentos de La Seo y El Pilar, los chapiteles de sus torres, las columnas de los porches del Mercado Central, las estructuras metâ”œÃ­licas en los palcos del Teatro Principal... En la imagen, salida de obreros de la fundiciâ”œâ”‚n, porque Averly tambiâ”œÂ®n fue cantera del movimiento obrero organizado en la ciudad. Fuente visual: Archivo Averly.', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65443700, -0.89371200, '0101000020E6100000395E81E84999ECBF6C257497C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14787924160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14787924160.webp', 'https://www.flickr.com/photos/zaragozaantigua/14787924160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23320, 'Campo Sepulcro. Proyecto 1896', 'Alzado del proyecto de la estaciâ”œâ”‚n ferroviaria "definitiva" de Zaragoza, denominada de Campo Sepulcro.', 1896, 1896, 1896, 'Siglo XIX', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14856811727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14856811727.webp', 'https://www.flickr.com/photos/zaragozaantigua/14856811727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23321, 'Estaciâ”œâ”‚n Campo Sepulcro 1960', 'Antigua estaciâ”œâ”‚n de Madrid. 1960. La estrecha calle de la izquierda separa el conjunto de la estaciâ”œâ”‚n de la fâ”œÃ­brica Escoriaza.', 1960, 1960, 1960, 'Anos 60', 'DELICIAS', 41.65366200, -0.89650000, '0101000020E6100000E3A59BC420B0ECBFA8514832ABD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14933958096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14933958096.webp', 'https://www.flickr.com/photos/zaragozaantigua/14933958096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23326, 'Campo Sepulcro c.1967', 'Imagen del edificio principal de la estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro o Madrid. Al fondo, a la derecha, los modernos y verticales bloques esquineros entre las calles del Tenor Gayarre, y Manuel Escoriaza y Fabro, e inmediatos a Viasa, y Alsoviasa.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15845267499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15845267499.webp', 'https://www.flickr.com/photos/zaragozaantigua/15845267499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23328, 'Fundiciâ”œâ”‚n Averly c.1903', 'Dibujo de las instalaciones de la fâ”œÃ­brica de fundiciones Averly de Zaragoza, en el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n nâ”¬â•‘ 59. Empresa fundada en 1880. Fuente visual: Gente de orden, Ibercaja, 1997.', 1903, 1903, 1903, 'Anos 1900', 'DELICIAS', 41.65443700, -0.89371200, '0101000020E6100000395E81E84999ECBF6C257497C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20185724960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20185724960.webp', 'https://www.flickr.com/photos/zaragozaantigua/20185724960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23330, 'Campo Sepulcro 1895', 'Fototipia Lucas Escolâ”œÃ­, 1895. Construcciâ”œâ”‚n de la definitiva Estaciâ”œâ”‚n de Campo Sepulcro, o de los Directos, de la lâ”œÂ¡nea MZA (durante casi 29 aâ”œâ–’os hubo una provisional estaciâ”œâ”‚n, unas decenas de metros mâ”œÃ­s al norte, donde los talleres). Serâ”œÃ­ inaugurada en 1896. La imagen estâ”œÃ­ capturada desde el Camino de Herederos, junto a una torre agrâ”œÂ¡cola donde casi 20 aâ”œâ–’os despuâ”œÂ®s serâ”œÃ­ construida la fâ”œÃ­brica de chocolates Ã”Ã‡Â£Casa Orâ”œâ•‘sÃ”Ã‡Ã˜. Fuente visual: www.facebook.com/photo.php?fbid=879415128747780&set=g...', 1895, 1895, 1895, 'Siglo XIX', 'DELICIAS', 41.65241500, -0.89512900, '0101000020E610000019709692E5A4ECBFBD35B05582D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20973707464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20973707464.webp', 'https://www.flickr.com/photos/zaragozaantigua/20973707464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23331, 'Campo Sepulcro 1849', '"Plano del Campo del Sepulcro en Zaragoza con el amojonamiento del terreno propio del ramo de guerra, segâ”œâ•‘n las escrituras de venta que obran en el archivo de la Direcciâ”œâ”‚n Subinspecciâ”œâ”‚n de Ingenieros", Joaquâ”œÂ¡n Gironza, Zaragoza, 28 de junio de 1849. Lâ”œÂ¡mites de la propiedad militar del Campo del Sepulcro de Zaragoza, entre el camino de la Casa Blanca (actual avenida Anselmo Clavâ”œÂ®) y el camino de Ronda (actual paseo de Marâ”œÂ¡a Agustâ”œÂ¡n). Fuente: AMZ.', 1849, 1849, 1849, 'Siglo XIX', 'DELICIAS', 41.65283200, -0.89287600, '0101000020E6100000F6436CB07092ECBF21E4BCFF8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21036546012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21036546012.webp', 'https://www.flickr.com/photos/zaragozaantigua/21036546012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23332, 'Campo Sepulcro 1961', 'Vâ”œÂ¡as de trâ”œÃ­nsito y convoy estacionado junto a la estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro. Al fondo, a la derecha, Anselmo Clavâ”œÂ® y una parcial vista del antiguo edificio de la Casa de Convalecientes, que desde finales de los aâ”œâ–’os cincuenta estaba ocupado por el Colegio Politâ”œÂ®cnico Nuestra Seâ”œâ–’ora del Pilar. Fuente visual: Trevor Rowe, Archivo EuskoTren/Museo Vasco del Ferrocarril.', 1961, 1961, 1961, 'Anos 60', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23633262179.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23633262179.webp', 'https://www.flickr.com/photos/zaragozaantigua/23633262179/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23334, 'Averly 1909', 'La fundiciâ”œâ”‚n de Antonio Averly llevaba desde 1880 instalada en la industrial zona de Campo Sepulcro, inmediata a la estaciâ”œâ”‚n de ferrocarril de ese nombre. En 1903, la empresa pasâ”œâ”‚ a denominarse "Hijos de A. Averly", y desde 1918, "Averly, S.A." De acuerdo con la teorâ”œÂ¡a microbiana del contagio, las medidas de profilaxis frente a la transmisiâ”œâ”‚n de enfermedades infecciosas se convirtieron en los albores del siglo XX en uno de los pilares bâ”œÃ­sicos de la moderna actuaciâ”œâ”‚n sanitaria. Y aplicar la desinfecciâ”œâ”‚n requiriâ”œâ”‚ nuevos equipos y materiales acordes, que en Averly pronto estuvieron prestos a fabricar y ofrecer al mercado. De esta forma, los grandes talleres de fundiciâ”œâ”‚n y construcciâ”œâ”‚n general de mâ”œÃ­quinas Averly, incluyeron en su catâ”œÃ­logo, y dentro de la categorâ”œÂ¡a "material sanitario", una extensa relaciâ”œâ”‚n de ofertas: estufas fijas y mâ”œâ”‚viles de desinfecciâ”œâ”‚n, pulverizadores, generadores de vapor-formol, esterilizadores, legiadoras, desinfectadoras, carros de transporte... Estos productos estaban destinados a hospitales, lazaretos, sanatorios, lavaderos, penitenciarâ”œÂ¡as, colegios... y Averly atendâ”œÂ¡a a cualquier solicitud de informaciâ”œâ”‚n, o de presupuesto, desde el apartado postal nâ”¬â•‘ 36, y el telâ”œÂ®fono nâ”¬â•‘ 49. En la imagen, un "generador de vapor formol" de tracciâ”œâ”‚n animal construido de Averly, para desinfecciâ”œâ”‚n de todo tipo de tejidos (mantas, colchones, ropa...) mediante la inyecciâ”œâ”‚n de agua con formol a mâ”œÃ­s de 110 grados centâ”œÂ¡grados, durante unos 15 minutos. Fuente visual: Revista "El Monitor Sanitario", Madrid.', 1909, 1909, 1909, 'Anos 1900', 'DELICIAS', 41.65435000, -0.89404300, '0101000020E6100000A1F7C610009CECBF9D11A5BDC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28020637115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28020637115.webp', 'https://www.flickr.com/photos/zaragozaantigua/28020637115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23336, 'Campo Sepulcro 1963', 'Imagen de una locomotora a vapor, posiblemente de la serie "1400", pasando frente al andâ”œÂ®n principal de la estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro, en direcciâ”œâ”‚n sur, hacia Miraflores. Detrâ”œÃ­s de ella, el muro perimetral de las enormes instalaciones de la empresa Carde y Escoriaza y, a la izquierda, fuera de plano, la vâ”œÂ¡a de conexiâ”œâ”‚n por donde salâ”œÂ¡a el material rodante allâ”œÂ¡ fabricado. Fuente visual: es.slideshare.net/', 1963, 1963, 1963, 'Anos 60', 'DELICIAS', 41.65167300, -0.89558800, '0101000020E6100000E014562AA8A8ECBFD65757056AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30684647422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30684647422.webp', 'https://www.flickr.com/photos/zaragozaantigua/30684647422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23337, 'Campo Sepulcro 1963', 'Imagen de una locomotora a vapor de la MZA, serie 741/780, construida en el Primer Reich alemâ”œÃ­n durante la primera dâ”œÂ®cada del siglo, tirando de un convoy en direcciâ”œâ”‚n a Madrid, delante de las naves y muelles cubiertos localizados en la manzana con forma de quesito entre la calle del Trovador (derecha), y la avenida de Madrid (izquierda). Esta fachada luego serâ”œÂ¡a completamente reedificada de nueva planta, con altos bloques de edificios. A la derecha de la imagen, fuera de plano, se encontraba la amplia zona de muelles de Campo Sepulcro. Fuente visual: image.slidesharecdn.com/', 1963, 1963, 1963, 'Anos 60', 'DELICIAS', 41.65463100, -0.89663900, '0101000020E61000003C2EAA4544B1ECBF51F9D7F2CAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30737601581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30737601581.webp', 'https://www.flickr.com/photos/zaragozaantigua/30737601581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23338, 'Estaciâ”œâ”‚n de Madrid 1965', 'Foto: Juliâ”œÃ­n Beguerâ”œÂ¡a Cervero. Acceso a la estaciâ”œâ”‚n de Madrid o Campo Sepulcro, desde la avenida de Josâ”œÂ® Anselmo Clavâ”œÂ® (a la espalda del fotâ”œâ”‚grafo). El niâ”œâ–’o se llama Javier Tregâ”œâ”‚n. A la estaciâ”œâ”‚n le quedaban siete aâ”œâ–’os. Fuente: Heraldo de Aragâ”œâ”‚n.', 1965, 1965, 1965, 'Anos 60', 'DELICIAS', 41.65234100, -0.89489400, '0101000020E6100000395FECBDF8A2ECBF836BEEE87FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31582125454.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31582125454.webp', 'https://www.flickr.com/photos/zaragozaantigua/31582125454/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23339, 'Campo Sepulcro c.1900', 'La fundiciâ”œâ”‚n Averly en su ubicaciâ”œâ”‚n de Campo Sepulcro, cercana al ferrocarril de la lâ”œÂ¡nea MZA, en una imagen capturada frente a su entrada principal desde la "travesâ”œÂ¡a" de la carretera de Madrid a Francia, luego redenominada paseo de Marâ”œÂ¡a Agustâ”œÂ¡n, donde ademâ”œÃ­s estaba ubicada la zona de vivienda fabril, con su correspondiente y ajardinado hotelito, en primer plano. Al fondo, y a la derecha, la zona productiva, con la fundiciâ”œâ”‚n, taller de maquinaria, y almacâ”œÂ®n de modelos-carpinterâ”œÂ¡a. Fuente visual: "Andalâ”œÃ­n, periâ”œâ”‚dico quincenal aragonâ”œÂ®s".', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65432600, -0.89364600, '0101000020E61000005D70067FBF98ECBF147651F4C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31877248433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31877248433.webp', 'https://www.flickr.com/photos/zaragozaantigua/31877248433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23341, 'Estaciâ”œâ”‚n Campo Sepulcro 1908', 'Carroza del rey Alfonso XIII ante la estaciâ”œâ”‚n de Campo Sepulcro, durante su visita en 1908. Fuente: Heraldo de Aragâ”œâ”‚n.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65216500, -0.89502900, '0101000020E610000037177FDB13A4ECBF444C89247AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32430948433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32430948433.webp', 'https://www.flickr.com/photos/zaragozaantigua/32430948433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23342, 'Estatua del Justicia 1899', 'Estatua del Justicia Juan de Lanuza, para el monumento diseâ”œâ–’ado por Fâ”œÂ®lix Navarro, fundida en Averly. Estâ”œÃ­ a la espera de que se coloque en 1904 en la glorieta de Pignatelli, que serâ”œÃ­ entonces redenominada plaza de Aragâ”œâ”‚n. Fuente: Revista Nuevo Mundo, 1899.', 1899, 1899, 1899, 'Siglo XIX', 'DELICIAS', 41.65435000, -0.89404300, '0101000020E6100000A1F7C610009CECBF9D11A5BDC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32697415680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32697415680.webp', 'https://www.flickr.com/photos/zaragozaantigua/32697415680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23343, 'Campo Sepulcro 1908', 'Vista del Campo Sepulcro en 1908, con las tropas formadas durante la visita de Alfonso XIII. Al fondo el cuartel de los Trinitarios (antiguo convento) y la gran torre cuadrangular de la facultad de Medicina y Ciencias. A la izquierda, paseo de Marâ”œÂ¡a Agustâ”œÂ¡n. Abajo, vâ”œÂ¡as del tranvâ”œÂ¡a a la estaciâ”œâ”‚n de Cariâ”œâ–’ena, en la actual avenida de Josâ”œÂ® Anselmo Clavâ”œÂ®. Fuente visual: revista "Ilustraciâ”œâ”‚n militar. Ejâ”œÂ®rcito y Marina".', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65280300, -0.89290000, '0101000020E610000018265305A392ECBF87DD770C8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33203571146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33203571146.webp', 'https://www.flickr.com/photos/zaragozaantigua/33203571146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23344, 'Campo Sepulcro c.1896', 'Imagen de la nueva estaciâ”œâ”‚n de los Directos en Campo Sepulcro, o estaciâ”œâ”‚n de Madrid, con detalle del inmediato espacio, a la derecha, donde estaba prevista la construcciâ”œâ”‚n del depâ”œâ”‚sito de locomotoras a vapor. A la izquierda, tras el mar de vâ”œÂ¡as, algunas de las Torres del camino de Herederos, al norte del barrio de Cariâ”œâ–’ena. Fuente visual: Guâ”œÂ¡a de Zaragoza 1902.', 1896, 1896, 1896, 'Siglo XIX', 'DELICIAS', 41.65221000, -0.89485300, '0101000020E6100000954737C2A2A2ECBFE40F069E7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34458892294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34458892294.webp', 'https://www.flickr.com/photos/zaragozaantigua/34458892294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23346, 'Campo Sepulcro 1966', 'Imagen centrada en el paso por el mar de vâ”œÂ¡as de la estaciâ”œâ”‚n Zaragoza-Campo Sepulcro de la moderna locomotora diesel, primera de la serie 352 de las "Vâ”œÂ¡rgenes" y denominada "Virgen del Rosario", tirando de una rama del Talgo III en direcciâ”œâ”‚n a la condal Barcelona. La vistosa combinaciâ”œâ”‚n de los colores rojo y plata en esta composiciâ”œâ”‚n, dicen que constituâ”œÂ¡a todo un espectâ”œÃ­culo para la vista. En 2002 esta locomotora fue dada de baja del servicio, y desguazada, y parece ser que la cabina perdura en el Museo del Ferrocarril de Arganda del Rey, porque los museos del ferrocarril, haberlos haylos. A la izquierda, naves del complejo fabril de Material Mâ”œâ”‚vil y Construcciones. En el centro, la veterana estaciâ”œâ”‚n, con un convoy estacionado y tirado, posiblemente, por una locomotora vaporosa de la serie 401/414. A la derecha e inmediata, aunque fuera de plano, el depâ”œâ”‚sito de locomotoras de vapor. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65147300, -0.89538400, '0101000020E6100000C092AB58FCA6ECBF0F9D9E7763D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39801337703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39801337703.webp', 'https://www.flickr.com/photos/zaragozaantigua/39801337703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23348, 'Campo Sepulcro 1968', 'Ferroviaria estampa capturada en la estaciâ”œâ”‚n de Zaragoza-Campo Sepulcro, cuyo edificio y andâ”œÂ®n principal queda a la izquierda. Centra la imagen un convoy de pasajeros tirado por una locomotora a vapor Mikado, y encaminado en direcciâ”œâ”‚n a Logroâ”œâ–’o. Hacia el fondo destacan las dos torrecillas de Industrias del Cartonaje S.A., antigua fâ”œÃ­brica de chocolates Orâ”œâ•‘s, y algunos de los modernos bloques levantados en el entorno de la moderna avenida de Goya. A la derecha, naves del complejo fabril de Material Mâ”œâ”‚vil y Construcciones. Fuente visual: foto Charles F. Firminger en "30937 Transport Photograph Database".', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65147300, -0.89538400, '0101000020E6100000C092AB58FCA6ECBF0F9D9E7763D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46962853502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46962853502.webp', 'https://www.flickr.com/photos/zaragozaantigua/46962853502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23349, 'Campo Sepulcro 1910', 'Imagen capturada en el campo de balompiâ”œÂ® habilitado en Campo Sepulcro y centrada en el "primer team" de la nueva sociedad "Zaragoza Foot-Ball Club", constituida a principios de aâ”œâ–’o y que utlizaba el referido campo para jugar sus partidos. El nombre de "Foot-Ball Club" era habitual entre los equipos pioneros de este deporte en las diversas ciudades donde fueron surgiendo, como el que fue constituido con ese nombre en 1903, que es considerado el primer club local de esta disciplina deportiva en Zaragoza, si bien su vida activa finalizâ”œâ”‚ en 1904. En 1910 surgiâ”œâ”‚ una nueva sociedad que incorporâ”œâ”‚ "Zaragoza" al nombre de aquella "Foot-Ball Club", si bien mantuvo su carâ”œÃ­cter "amateur" y, a la postre, efâ”œÂ¡mero. En 1912 este equipo llegâ”œâ”‚ a inaugurar su propio terreno de juego en el perifâ”œÂ®rico camino de San Josâ”œÂ®, cedido temporalmente por su propietario, el comerciante Francisco Agelet, si bien terminâ”œâ”‚ sus dâ”œÂ¡as jugando en el "campo de los alemanes" de la calle de Bilbao.', 1910, 1910, 1910, 'Anos 10', 'DELICIAS', 41.65116600, -0.89268200, '0101000020E6100000BA4A77D7D990ECBF3222516859D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53461103455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53461103455.webp', 'https://www.flickr.com/photos/zaragozaantigua/53461103455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23350, 'Campo Sepulcro 1967', 'Imagen capturada ante el puente giratorio del depâ”œâ”‚sito de locomotoras sito en la estaciâ”œâ”‚n de Zaragoza-Campo Sepulcro, y centrada en un agostino intercambio ferroviario de pareceres, con el fondo de dos vaporosas Renfe 141 o "Mikado" y una Renfe 2701.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65125400, -0.89416200, '0101000020E6100000336E6AA0F99CECBFD1B1834A5CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54226615682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54226615682.webp', 'https://www.flickr.com/photos/zaragozaantigua/54226615682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23694, 'Sanatorio San Jorge 1966', 'En 1920 el arquitecto Miguel â”œÃ¼ngel Navarro diseâ”œâ–’â”œâ”‚ una vivienda para la familia Monterde en la calle Marcelino Domingo (Padre Manjâ”œâ”‚n, tras el 18 de julio de 1936) del Barrio de la Explanada, muy cerca del enlace del ferrocarril de Cariâ”œâ–’ena con la estaciâ”œâ”‚n de Campo Sepulcro. El edificio estaba definido en un estilo neorregionalista que incorporaba elementos del repertorio modernista. Mâ”œÃ­s tarde fue bastante modificado y ampliado, segâ”œâ•‘n los distintos usos que se le fueron dando. En la abrileâ”œâ–’a imagen, el edificio funcionando como "Sanatorio S. Jorge. Obra Sindical 18 de Julio". Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65341000, -0.90171500, '0101000020E610000026016A6AD9DAECBF8F705AF0A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15217731081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15217731081.webp', 'https://www.flickr.com/photos/zaragozaantigua/15217731081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23644, '&quot;Feliz Navidad&quot; 1938', 'En fechas seâ”œâ–’aladamente entraâ”œâ–’ables, una oximorâ”œâ”‚nica estampa navideâ”œâ–’a con uno los soldados alemanes de la Luftwaffe encuadrados en la denominada "Legiâ”œâ”‚n Câ”œâ”‚ndor", durante su destino en el Aerâ”œâ”‚dromo de Sanjurjo de la ciudad, cuando funcionaba como base aâ”œÂ®rea de utilizaciâ”œâ”‚n conjunta, en este caso hispano-germano-italiana, desde 1937. "Feliz Navidad" ("Frohe Weihnachten"), y algo parecido al trazo de unos cristales de nieve, iluminan y llenan de sentimiento el posado junto a dos, entre otros proyectiles de menor calibre, impactantes artefactos explosivos de bombardeo empleados por la fuerza aâ”œÂ®rea nazi destacada en apoyo de la Espaâ”œâ–’a nacionalista.', 1938, 1938, 1938, 'Anos 30', NULL, 41.66303700, -1.02413100, '0101000020E6100000CD1DFD2FD762F0BFDC847B65DED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15811716717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15811716717.webp', 'https://www.flickr.com/photos/zaragozaantigua/15811716717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23709, 'Calle de Graus 1932', 'Imagen de la parcela del nâ”¬â•‘ 6 de la calle Graus, en el barrio de las Delicias, donde fueron detenidas cuatro personas por posesiâ”œâ”‚n de metralla y componentes quâ”œÂ¡micos (clorato de potasa, glicerina, azufre, â”œÃ­cido sulfâ”œâ•‘rico...) susceptibles de ser utilizados para fabricar bombas y explosivos. Los detenidos fueron puestos a disposiciâ”œâ”‚n judicial. La parcela-polvorâ”œÂ¡n estaba ubicada muy cerca de la calle de Unceta, y casi frente al solar donde dos aâ”œâ–’os mâ”œÃ­s tarde los escolapios construirâ”œÂ¡an la primera iglesia parroquial de San Valero, que tambiâ”œÂ®n contaba con un local para escuelas, que llegâ”œâ”‚ a albergar a 80 alumnos. Iglesia y escuela estuvieron activas hasta 1939, en que cerraron. Una nueva iglesia parroquial de San Valero se levantarâ”œÂ¡a en los aâ”œâ–’os 40, y buena parte de su mobiliario procedâ”œÂ¡a de la derribada iglesia de San Andrâ”œÂ®s Apâ”œâ”‚stol. Fuente visual: Foto Martâ”œÂ¡nez ("Mundo Grâ”œÃ­fico", Madrid).', 1932, 1932, 1932, 'Anos 30', 'DELICIAS', 41.65257900, -0.90268000, '0101000020E6100000DF1AD82AC1E2ECBF38876BB587D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21440630243.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21440630243.webp', 'https://www.flickr.com/photos/zaragozaantigua/21440630243/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23717, 'Av. de Madrid 1976', 'Imagen capturada en la avenida de Madrid junto al cine Madrid (izquierda), inaugurado en 1955 con proyecto del arquitecto Eduardo Lagunilla. Este cine fue clausurado unos aâ”œâ–’os mâ”œÃ­s tarde, en 1984, y el amplio local reconvertido en centro de fomento de la ludopatâ”œÂ¡a. A la derecha, irrepetible imagen de la antigua fachada de los nâ”œâ•‘meros pares de la avenida desde el nâ”œâ•‘mero 36 hasta la calle del Arzobispo Aâ”œâ–’oa de Busto, cuyo moderno nâ”œâ•‘mero 1 (antiguo 44 de la avenida) estâ”œÃ­ en pleno proceso de descontextualizada construcciâ”œâ”‚n, al uso de la â”œÂ®poca. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.65413400, -0.90177800, '0101000020E6100000BE1248895DDBECBFD099B4A9BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27802236399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27802236399.webp', 'https://www.flickr.com/photos/zaragozaantigua/27802236399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21509, 'Cabezo de Buena Vista c.1926', 'Patrimonio Cultural Universidad de Zaragoza. Luis Gandâ”œâ•‘ Mercadal. Ca. 1926. Paseo por Cabezo de Buena Vista una fresca maâ”œâ–’ana de invierno. En la imagen, Mâ”¬Â¬ Luisa Gandâ”œâ•‘ Dorel, hija de Luis Gandâ”œâ•‘ Mercadal. Detrâ”œÃ­s de ellas, la ciudad de Zaragoza vista desde este Cabezo. Fuente visual: patrimoniocultural.unizar.es/node/3153', 1926, 1926, 1926, 'Anos 20', 'UNIVERSIDAD', 41.63246000, -0.89215300, '0101000020E6100000BCE7C072848CECBF9B030473F4D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15649014151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15649014151.webp', 'https://www.flickr.com/photos/zaragozaantigua/15649014151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23729, 'Av. de Madrid 1979', 'Imagen del incuestionable absolutismo del motor en la â”œÂ®poca, tramo de la avenida de Madrid justo al lado del despartidero (a la derecha) que mojoneaba el arranque de la avenida de Navarra, y que se mantenâ”œÂ¡a como barbecho urbanâ”œÂ¡stico usufructuado mientras tanto por comerciales diversos, incluyendo propaganda electoral del Partido del Trabajo de Aragâ”œâ”‚n, ilustrada con la imagen de su candidato cabecero a las Elecciones Generales de 1979, el secretario general de la Confederaciâ”œâ”‚n de Sindicatos Unitarios de Trabajadores, CSUT , Jerâ”œâ”‚nimo Lorente Hernâ”œÃ­ndez. A la izquierda, imagen del antiguo nâ”¬â•‘ 117 de la avenida, luego sustituido por un moderno bloque hasta cuatro veces mâ”œÃ­s alto. Fuente visual: Banco de Imâ”œÃ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œÂ®, amablemente cedida para el', 1979, 1979, 1979, 'Anos 70', 'DELICIAS', 41.65439600, -0.90136100, '0101000020E6100000B3791C06F3D7ECBF0D51853FC3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33191005256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33191005256.webp', 'https://www.flickr.com/photos/zaragozaantigua/33191005256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23731, 'Delicias c.1925', 'Imagen capturada desde la altura de la fâ”œÃ­brica de Carde y Escoriaza inmediata a la estaciâ”œâ”‚n ferroviaria de Campo Sepulcro, orientada hacia el oeste, con una interesante panorâ”œÃ­mica de la barriada de las Delicias. En primer tâ”œÂ®rmino, y tras el ramal del Boquerazo de la acequia de la Romareda, antiguos campos de Tarongi y de la Torre de Domingo. En el centro de la imagen, el referencial remate que culminaba la casa de la familia Monterde en la calle de Marcelino Domingo. Al fondo a la izquierda, la casa de la familia Palomar destaca desde su dominante emplazamiento natural. Fuente visual: Archivo CAF (AHPZ-DARA)', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.65305400, -0.90008200, '0101000020E610000016FC36C478CDECBFD042024697D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37768583714.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37768583714.webp', 'https://www.flickr.com/photos/zaragozaantigua/37768583714/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23733, 'Calle del Padre Manjâ”œâ”‚n 1980', 'En 1920 el arquitecto Miguel â”œÃ¼ngel Navarro diseâ”œâ–’â”œâ”‚ una destacada vivienda para la familia Monterde en la calle Marcelino Domingo (redenominada del Padre Andrâ”œÂ®s Manjâ”œâ”‚n, tras el 18 de julio de 1936) del barrio de la Explanada, muy cerca del enlace del ferrocarril de Cariâ”œâ–’ena con la estaciâ”œâ”‚n de Campo Sepulcro. Este edificio estaba definido en un estilo neorregionalista que incorporaba elementos del repertorio modernista. Mâ”œÃ­s tarde fue bastante modificado y ampliado, segâ”œâ•‘n los distintos usos que se le fueron dando con el paso del tiempo. En la imagen, el inmueble funcionando como "Clâ”œÂ¡nica San Jorge de la SS (Seguridad Social)" del Instituto Nacional de la Salud (INSALUD), heredero del previo Instituto Nacional de Previsiâ”œâ”‚n. Fuente visual: AMZ', 1980, 1980, 1980, 'Anos 80', 'DELICIAS', 41.65341000, -0.90171500, '0101000020E610000026016A6AD9DAECBF8F705AF0A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41283023180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41283023180.webp', 'https://www.flickr.com/photos/zaragozaantigua/41283023180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23922, 'Cuartel de El Cid 1968', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 1968. Imagen del interior de los patios del antiguo Cuartel de Caballerâ”œÂ¡a de El Cid, tras el derribo de sus instalaciones. Al fondo, a la izquierda, la Iglesia de El Portillo, y las traseras de algunas viviendas de la plaza. A la derecha, sobresale levemente la torre-câ”œâ•‘pula de la sucursal de una entidad bancaria local. Una buena parte de los solares resultantes siguen a la espera de un destino urbanizado.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65435600, -0.89290700, '0101000020E6100000B7D26BB3B192ECBF7FF8F9EFC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15030027708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15030027708.webp', 'https://www.flickr.com/photos/zaragozaantigua/15030027708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23932, 'Cuartel del Cid 1968', 'Imagen capturada desde el interior de una de las estancias que se abrâ”œÂ¡an al patio del antiguo Cuartel de Caballerâ”œÂ¡a de El Cid, cuando estaba siendo derribado tras haber sido despojado de sus funciones castrenses, tal y como era tradiciâ”œâ”‚n desde que fuera construido allâ”œÃ­ en los remotos tiempos de la Ilustraciâ”œâ”‚n. Al fondo, sobresale levemente la torre-câ”œâ•‘pula de la sucursal de una entidad bancaria local, esquinada entre la plaza del Portillo y General Franco. 47 aâ”œâ–’os despuâ”œÂ®s, de momento, buena parte del gran solar resultante sigue esperando alguna finalidad. Tampoco hay ningâ”œâ•‘n panel informativo arqueolâ”œâ”‚gico que avise de lo que esto fuera, o fuese, por si a alguien, de forma accidental, o harto improbable, llegara a interesarle. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65458000, -0.89325100, '0101000020E610000046D1031F8395ECBFCF4E0647C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23820032459.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23820032459.webp', 'https://www.flickr.com/photos/zaragozaantigua/23820032459/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23936, 'P.â”¬â•‘ de Marâ”œÂ¡a Agustâ”œÂ¡n 1965', '"Vista de Zaragoza desde el estudio", â”œâ”‚leo sobre lienzo, Luis Esteban Ramâ”œâ”‚n, ca. 1965, Interesante visual desde el tramo del paseo de Marâ”œÂ¡a Agustâ”œÂ¡n comprendido entre la calle del General Franco y la de Josâ”œÂ® Anselmo Clavâ”œÂ®. Abajo, instalaciones del cuartel del Cid. Al fondo, alturas de la ciudad, entre el torreâ”œâ”‚n de la plaza del Portillo 2 y la câ”œâ•‘pula de San Ildefonso, tras la plaza de Toros. Fuente visual: zaragozacool.wordpress.com', 1965, 1965, 1965, 'Anos 60', 'DELICIAS', 41.65460200, -0.89321800, '0101000020E6100000575A46EA3D95ECBFB6F292FFC9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26245745327.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26245745327.webp', 'https://www.flickr.com/photos/zaragozaantigua/26245745327/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24195, 'Estaciâ”œâ”‚n Campo Sepulcro 1933', 'Estaciâ”œâ”‚n de ferrocarril Campo Sepulcro, de la compaâ”œâ–’â”œÂ¡a MZA. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'DELICIAS', 41.65241500, -0.89512900, '0101000020E610000019709692E5A4ECBFBD35B05582D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23217883536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23217883536.webp', 'https://www.flickr.com/photos/zaragozaantigua/23217883536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24201, 'Campo Sepulcro c.1920', 'Imagen de la nueva vâ”œÂ¡a de conexiâ”œâ”‚n entre las instalaciones fabriles de los talleres de Carde y Escoriaza (al fondo), y la estaciâ”œâ”‚n Campo Sepulcro del ferrocarril MZA. Las puertas han sido abiertas, y una locomotora a vapor (posiblemente una 100 con caldera renovada) enfila la curva de acceso ferroviario tirando de material rodante reciâ”œÂ®n terminado. La maniobra, bajo un sol cenital, es seguida atentamente por operarios, tancredos, y pâ”œâ•‘blico en general. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (CAF), AHPZ.', 1920, 1920, 1920, 'Anos 20', 'DELICIAS', 41.65272800, -0.89660900, '0101000020E61000009293895B05B1ECBF7D9752978CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31690153993.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31690153993.webp', 'https://www.flickr.com/photos/zaragozaantigua/31690153993/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24463, 'Campo Sepulcro 1924', 'Almacenes de Carbones Pina, de Juan Pâ”œÂ®rez Herrero, en las instalaciones de la Estaciâ”œâ”‚n Ferroviaria de Campo Sepulcro de Zaragoza, con su propio apartadero, en 1924. Fuente: La Esfera, 3 de enero de 1925.', 1924, 1924, 1924, 'Anos 20', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20038867901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20038867901.webp', 'https://www.flickr.com/photos/zaragozaantigua/20038867901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24474, 'Talleres Carde y Escoriaza c.1945', 'Pintura del complejo de la fâ”œÃ­brica de Carde y Escoriaza en su ubicaciâ”œâ”‚n junto a la estaciâ”œâ”‚n de Campo Sepulcro. Permaneciâ”œâ”‚ allâ”œÂ¡ desde los aâ”œâ–’os 20 hasta los 70, fabricando material pesado, como ferrocarriles y tranvâ”œÂ¡as. Fuente: "150 aâ”œâ–’os de ferrocarril en Zaragoza", 2011.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.65196900, -0.89757100, '0101000020E610000007D15AD1E6B8ECBFBF805EB873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20587697371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20587697371.webp', 'https://www.flickr.com/photos/zaragozaantigua/20587697371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24871, 'Estaciâ”œâ”‚n de Campo Sepulcro c.1945', 'Imagen capturada en el punto de situado o lugar autorizado de parada de coches de punto a tracciâ”œâ”‚n animal en la estaciâ”œâ”‚n de Campo Sepulcro o de Madrid, ubicado justo frente al edificio principal de la estaciâ”œâ”‚n al que se accedâ”œÂ¡a por la derecha desde la calle de Anselmo Clavâ”œÂ®. En ese momento perduraban unos 25 coches de punto en activo, al precio de 5 pesetas la hora para tres personas o 6 pesetas la hora para cuatro. El â”œâ•‘ltimo de estos vehâ”œÂ¡culos fue retirado del servicio en 1957.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.65259300, -0.89482700, '0101000020E6100000467D923B6CA2ECBF9D4CDC2A88D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54982028592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54982028592.webp', 'https://www.flickr.com/photos/zaragozaantigua/54982028592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25062, 'Dos generales y un Alcalde 1927', 'Ayuntamiento de Zaragoza/Foto A. de la Barrera. "General Primo de Rivera". El Alcalde de la ciudad, Miguel Alluâ”œÂ® Salvador (sentado a la izquierda), recoge en la Estaciâ”œâ”‚n Campo Sepulcro, en carruaje oficial, al General y Dictador Miguel Primo de Rivera y Orbaneja, y al general Josâ”œÂ® Sanjurjo Sacanell. Todos sonrâ”œÂ¡en mucho. Datada y comentada por el proyecto GAZA ("Gran Archivo Zaragoza Antigua"), es un compendio de imâ”œÃ­genes de la antigua Zaragoza (Espaâ”œâ–’a), acompaâ”œâ–’adas de textos creados por Josâ”œÂ® Marâ”œÂ¡a Ballestâ”œÂ¡n Miguel y la colaboraciâ”œâ”‚n de Antonio Tausiet. adioszaragoza.blogspot.com', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.65216800, -0.89483300, '0101000020E6100000CE35CCD078A2ECBFB6BFB33D7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14938013762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14938013762.webp', 'https://www.flickr.com/photos/zaragozaantigua/14938013762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25162, 'Doâ”œâ–’a Blanca de Navarra c.1948', 'Dibujo con la representaciâ”œâ”‚n de las nuevas instalaciones de la fâ”œÃ­brica de camas metâ”œÃ­licas y somieres Alfonso Solans Viamonte, en la calle de Navarra, barriada del Cigarral, en las Delicias. Hasta esta ubicaciâ”œâ”‚n se vino el negocio desde su emplazamiento original, fundado allâ”œÃ­ por 1927 en el arranque del camino de las Fuentes, inmediato a la calle Miguel Servet, cuando Alfonso Solans Viamonte se independizâ”œâ”‚ del negocio camero de su padre Froilâ”œÃ­n Solans Lerâ”œÂ¡n, e iniciâ”œâ”‚ el suyo propio. En este momento, su hijo Alfonso Solans Serrano estaba haciendo lo propio, e iniciaba su carrera empresarial en un local de la calle Santiago Lapuente. En el dibujo, la representaciâ”œâ”‚n de la calle de Navarra, en primer plano, es ciertamente fantasiosa, pues mâ”œÃ­s parece una avenida que el pequeâ”œâ–’o vial con entrada por la avenida de Madrid, y final brusco ante la fâ”œÃ­brica de Material Mâ”œâ”‚vil y Construcciones y el camino de la Mosquetera. Al poco tiempo, la empresa fue redenominada ALSOVISA (Alfonso Solans Viamonte, S.A.), y esta calle mudâ”œâ”‚ su nombre por el de Doâ”œâ–’a Blanca de Navarra para evitar confusiones con la nueva y prometedora avenida de Navarra. A la derecha, la calle del Tenor Gayarre, que la separarâ”œÃ­ de la planta de VIASA. A la izquierda, y tras el cierre de la fâ”œÃ­brica y posterior reurbanizaciâ”œâ”‚n de la zona a mediados de los aâ”œâ–’os 70, se abrirâ”œÃ­ la prolongaciâ”œâ”‚n de la calle Pablo Sarasate. Al fondo, el paso a nivel de las Delicias y vâ”œÂ¡as conducentes al entorno ferroviario de la estaciâ”œâ”‚n de Campo Sepulcro. Fuente visual: www.todocoleccion.net/', 1948, 1948, 1948, 'Anos 40', 'DELICIAS', 41.65345300, -0.89919300, '0101000020E61000001D59F96530C6ECBF8E3C1059A4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32107434036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32107434036.webp', 'https://www.flickr.com/photos/zaragozaantigua/32107434036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
