INSERT INTO public.photos VALUES (26036, 'El Portillo 1974', 'Imagen del acceso desde la calle de Josâ”œÂ® Anselmo Clavâ”œÂ® a la reciente estaciâ”œâ”‚n de ferrocarril Zaragoza-El Portillo, donde RENFE concentrâ”œâ”‚ todos los servicios que hasta ese momento prestaban las estaciones de Campo Sepulcro, Delicias, y Arrabal. Tras la moderna construcciâ”œâ”‚n, atisbos del mar de vâ”œÂ¡as de la estaciâ”œâ”‚n, y algunos edificios del entorno de la calle Escoriaza y Fabro, todavâ”œÂ¡a con las naves de la antigua fâ”œÃ­brica de Material Mâ”œâ”‚vil (derecha). A su lado, la descomunal urbanizaciâ”œâ”‚n Parque Roma progresa adecuadamente. La clara maâ”œâ–’ana permite una visual, incluso, del nuevo Hospital Clâ”œÂ¡nico Universitario, allâ”œÃ­ en la calle San Juan Bosco. Fuente visual: www.ebay.es/', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65167300, -0.89466500, '0101000020E6100000E2067C7E18A1ECBFD65757056AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31197955402.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31197955402.webp', 'https://www.flickr.com/photos/zaragozaantigua/31197955402/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20876, 'El Portillo 1119', 'Segâ”œâ•‘n D. Josef Fâ”œÂ®lix de Amada (1796), estaba Saragoâ”œÂºa reciâ”œÂ®n conquistada por Alfonso I y Gastâ”œâ”‚n de Bâ”œÂ®arn, cuando los moros, que son muy traidores, en gran turba y silencio, y aprovechando la oscuridad de la noche y un notable descuido de los cristianos (los guardas y centinelas estaban en brazos de morfeo), se colaron haciendo una brecha en la muralla de tapial frente a la Aljaferâ”œÂ¡a. Pero la virgen santâ”œÂ¡sima, que velaba por todos los suyos, incluso los descuidados, capitaneâ”œâ”‚ de repente un volante ejâ”œÂ®rcito de espâ”œÂ¡ritus celestiales en forma visible, y les repeliâ”œâ”‚ con el pavor de las soberanas luces que destellaban, y el sangriento estrago que les causâ”œâ”‚. Tamaâ”œâ–’a ruidera despertâ”œâ”‚ finalmente a los guardas, que dieron avisos que sâ”œâ”‚lo sirvieron para testificar el milagro producido: el contorno del Portillo estaba lleno de infinitos moros muertos, ademâ”œÃ­s de una pequeâ”œâ–’a imagen de la reina de los â”œÃ­ngeles que ella misma dejâ”œâ”‚ en la brecha de la muralla por donde se colaron los infieles, como prenda de su protecciâ”œâ”‚n y amparo. Los atâ”œâ”‚nitos lugareâ”œâ–’os celebraron la victoria, y acordaron levantar un magnâ”œÂ¡fico templo para resguardar la material imagen, con el tâ”œÂ¡tulo de Nuestra Seâ”œâ–’ora del Portillo. Acordaron ademâ”œÃ­s no reparar la muralla, que con la virgen bastaba. Los moros padecieron tan espantosa matanza, que ya no volvieron a intentarlo. En la xilografâ”œÂ¡a anâ”œâ”‚nima del siglo XVIII, representaciâ”œâ”‚n simplificada del milagro: a los pies del muro, unos moros se caen al suelo, derribados por la sobrenatural armada, cuya capitana destellea como sol, y eclipsa la brecha abierta. Fuente visual: Wifredo Rincâ”œâ”‚n Garcâ”œÂ¡a, "La Zaragoza de los Sitios", Colecciâ”œâ”‚n Editorial Fundaciâ”œâ”‚n Sitios nâ”¬â•‘ 4, 2008.', 1119, 1119, 1119, 'Siglo XIX', 'DELICIAS', 41.65595200, -0.89345400, '0101000020E6